import{_ as i,o as e,c as l,a2 as r}from"./chunks/framework.Cr-Z7ngm.js";const p=JSON.parse('{"title":"如何关闭或降低融资额度","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"margin/reduce-limit.md","filePath":"zh-CN/margin/reduce-limit.md"}'),t={name:"margin/reduce-limit.md"};function o(n,a,h,d,s,u){return e(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="如何关闭或降低融资额度" tabindex="-1">如何关闭或降低融资额度 <a class="header-anchor" href="#如何关闭或降低融资额度" aria-label="Permalink to &quot;如何关闭或降低融资额度&quot;">​</a></h1><p>长桥账户默认为融资账户（保证金账户）。如果您不需要使用杠杆交易，可以降低或关闭融资额度，以避免误操作产生融资利息。</p><h2 id="降低融资额度" tabindex="-1">降低融资额度 <a class="header-anchor" href="#降低融资额度" aria-label="Permalink to &quot;降低融资额度&quot;">​</a></h2><ol><li>打开长桥 App，进入「资产」页面</li><li>找到「融资状态」或「我的融资额度」</li><li>点击「调整额度」，将额度调低至您需要的金额</li><li>确认提交，24 小时内生效</li></ol><p>每 24 小时内最多申请 2 次（新加坡账户每 24 小时限 1 次）。</p><h2 id="关闭融资额度" tabindex="-1">关闭融资额度 <a class="header-anchor" href="#关闭融资额度" aria-label="Permalink to &quot;关闭融资额度&quot;">​</a></h2><p>将融资额度调整为 0 即等同关闭融资。关闭后账户仍为保证金账户，但不可使用杠杆买入。</p><p><strong>前提条件</strong>：关闭前需满足：</p><ul><li>账户内无未平仓的融资持仓（即无结欠资金）</li><li>无待成交的融资买入委托</li></ul><p>如有融资持仓，需先卖出持仓并还清欠款后再申请关闭。</p><h2 id="确认是否有融资结欠" tabindex="-1">确认是否有融资结欠 <a class="header-anchor" href="#确认是否有融资结欠" aria-label="Permalink to &quot;确认是否有融资结欠&quot;">​</a></h2><p>进入 App → 资产 → 现金页，查看「融资余额」或「结欠」字段：</p><ul><li>如显示 0 或为空：无结欠，可直接关闭</li><li>如显示负数金额：账户有融资结欠，需先还清</li></ul><p>还清融资的方式：入金至账户后，系统将在下一个结算日自动扣除结欠；或通过换汇操作偿还不同币种的结欠。</p><h2 id="降低额度不影响既有持仓" tabindex="-1">降低额度不影响既有持仓 <a class="header-anchor" href="#降低额度不影响既有持仓" aria-label="Permalink to &quot;降低额度不影响既有持仓&quot;">​</a></h2><ul><li>降低额度不影响已有持仓，仅限制新增融资买入</li><li>持仓市值下跌导致维持保证金不足时，平台仍会发出追缴通知，与是否主动关闭额度无关</li><li>如需重新开启融资，按相同流程申请提高额度即可</li></ul><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/margin/融资额度与保证金规则">融资额度与保证金规则</a></li><li><a href="/margin/融资利息规则">融资利息规则</a></li><li><a href="/margin/账户风控状态">账户风控状态</a></li></ul>',18)])])}const m=i(t,[["render",o]]);export{p as __pageData,m as default};
